import{_ as e,o as l,c as o,a2 as r}from"./chunks/framework.BZO4qERu.js";const c=JSON.parse('{"title":"關於 Blades Game 游刃攻略","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),t={name:"about.md"};function i(n,a,h,d,s,p){return l(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="關於-blades-game-游刃攻略" tabindex="-1">關於 Blades Game 游刃攻略 <a class="header-anchor" href="#關於-blades-game-游刃攻略" aria-label="Permalink to &quot;關於 Blades Game 游刃攻略&quot;">​</a></h1><h2 id="這是什麼" tabindex="-1">這是什麼？ <a class="header-anchor" href="#這是什麼" aria-label="Permalink to &quot;這是什麼？&quot;">​</a></h2><p><strong>Blades Game 游刃攻略</strong> 是一個繁體中文遊戲攻略網站，專注於深度、原創、結構化的遊戲指南。</p><p>我們跟一般遊戲攻略站的差別：</p><ul><li>🎯 <strong>深度而非廣度：</strong> 一篇攻略從頭講到尾，而不是幾句零散心得</li><li>📊 <strong>數據驅動：</strong> 兵種對比、收益分析，全部有數字支撐</li><li>📍 <strong>具體地名：</strong> 每個村莊、每個城鎮、每個招募點都標清楚</li><li>🔄 <strong>持續更新：</strong> 跟隨遊戲版本更新，不讓攻略過時</li></ul><h2 id="為什麼叫「遊刃」" tabindex="-1">為什麼叫「遊刃」？ <a class="header-anchor" href="#為什麼叫「遊刃」" aria-label="Permalink to &quot;為什麼叫「遊刃」？&quot;">​</a></h2><p>取自成語「遊刃有餘」—— 玩遊戲就該輕鬆寫意，一刀到位。</p><p>不囉嗦、不搬運、不抄襲。每一篇都是親自遊玩後的原創心得。</p><h2 id="目前涵蓋" tabindex="-1">目前涵蓋 <a class="header-anchor" href="#目前涵蓋" aria-label="Permalink to &quot;目前涵蓋&quot;">​</a></h2><ul><li>⚔️ 騎馬與砍殺2：霸主（Mount &amp; Blade II: Bannerlord）</li></ul><h2 id="聯絡與授權" tabindex="-1">聯絡與授權 <a class="header-anchor" href="#聯絡與授權" aria-label="Permalink to &quot;聯絡與授權&quot;">​</a></h2><p>本站所有內容皆為原創，未經授權禁止轉載。 如需合作或授權，請來信：<em>（即將開通）</em></p><p>如果你發現攻略內容有誤或需要更新，請到 <a href="/feedback.html">內容回報頁</a> 告訴我們。</p><hr><h2 id="免責聲明" tabindex="-1">免責聲明 <a class="header-anchor" href="#免責聲明" aria-label="Permalink to &quot;免責聲明&quot;">​</a></h2><p>本站是《騎馬與砍殺2：霸主》及相關遊戲的非官方粉絲攻略站，內容僅供玩家參考。本站與 TaleWorlds Entertainment 或任何遊戲官方沒有合作、授權或代表關係。</p><h3 id="攻略與-mod-風險" tabindex="-1">攻略與 Mod 風險 <a class="header-anchor" href="#攻略與-mod-風險" aria-label="Permalink to &quot;攻略與 Mod 風險&quot;">​</a></h3><p>玩家環境可能因平台、版本、Mod、作業系統與硬體而不同。本站提供的教學、設定、Mod 說明、外部工具建議，無法保證適用於所有玩家。</p><p>請在進行以下操作前先備份存檔：</p><ul><li>安裝 Mod</li><li>修改遊戲設定</li><li>使用外部工具</li><li>更動遊戲檔案</li></ul><p>本站不對玩家個人存檔、遊戲安裝、Mod 衝突、電腦環境損壞或資料遺失負責。</p><h3 id="外部連結" tabindex="-1">外部連結 <a class="header-anchor" href="#外部連結" aria-label="Permalink to &quot;外部連結&quot;">​</a></h3><p>本站可能提供外部網站連結。外部網站內容與下載檔案由該網站或作者管理，本站無法保證其永久有效、安全或最新。</p><p>下載任何 Mod 或工具前，請優先選擇官方或原作者來源。</p><h3 id="商標與著作權" tabindex="-1">商標與著作權 <a class="header-anchor" href="#商標與著作權" aria-label="Permalink to &quot;商標與著作權&quot;">​</a></h3><p>本站提及的遊戲名稱、商標、角色、品牌與相關素材，權利屬於其各自權利人。本站使用相關名稱僅為攻略說明與玩家討論目的。</p><hr><h2 id="隱私權政策" tabindex="-1">隱私權政策 <a class="header-anchor" href="#隱私權政策" aria-label="Permalink to &quot;隱私權政策&quot;">​</a></h2><h3 id="我們可能收集的資料" tabindex="-1">我們可能收集的資料 <a class="header-anchor" href="#我們可能收集的資料" aria-label="Permalink to &quot;我們可能收集的資料&quot;">​</a></h3><p>當你瀏覽本站時，網站可能透過基本流量分析工具收集非個人識別資料，例如：</p><ul><li>瀏覽頁面</li><li>裝置與瀏覽器類型</li><li>大略地區</li></ul><p>如果你使用聯絡表單，本站可能收集你主動填寫的資料。</p><h3 id="我們如何使用資料" tabindex="-1">我們如何使用資料 <a class="header-anchor" href="#我們如何使用資料" aria-label="Permalink to &quot;我們如何使用資料&quot;">​</a></h3><p>這些資料可能用於改善網站內容、分析哪些攻略最需要更新。</p><p>本站不會主動販售你的個人資料。</p><h3 id="第三方服務" tabindex="-1">第三方服務 <a class="header-anchor" href="#第三方服務" aria-label="Permalink to &quot;第三方服務&quot;">​</a></h3><p>未來本站可能使用 Google Search Console、Google Analytics、Google AdSense。屆時本頁會依實際使用服務補充說明。</p><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。。</em></p>',39)])])}const m=e(t,[["render",i]]);export{c as __pageData,m as default};
